// Enhanced state initialization with validation
const input = $input.first().json;
const userInput = input.message || input.userInput || input.query || 'Default research request';
const priority = input.priority || 'normal'; // high, normal, low
const maxRounds = input.maxRounds || 4;
const consensusThreshold = input.consensusThreshold || 85;

// Initialize comprehensive state
const initialState = {
  // Core workflow state
  phase: 'research',
  round: 1,
  maxRounds,
  consensusThreshold,
  priority,
  status: 'active',

  // Document management
  documents: {
    research: null,
    analysis: null,
    plan: null
  },

  // Agent performance tracking
  agentPerformance: {
    active: ['qwen3', 'mistral', 'deepseek', 'nemotron', 'llama', 'kimi'],
    failed: [],
    timeout: [],
    scores: {}
  },

  // Refinement and consensus
  refinementHistory: [],
  consensusScores: [],
  divergencePoints: [],

  // User context
  userInput,
  timestamp: new Date().toISOString(),
  workflowId: `wf_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
};

// Validate input
if (!userInput || userInput.trim().length < 10) {
  throw new Error('User input must be at least 10 characters long');
}

return initialState;

// Dynamic prompt generation with context awareness
const state = $input.first().json;
const { phase, round, userInput, documents, refinementHistory, consensusScores } = state;

// Phase-specific prompt templates
const promptTemplates = {
  research: {
    system: 'You are a research specialist conducting comprehensive analysis.',
    objective: 'Conduct thorough research on the topic with reliable sources.',
    outputFormat: 'JSON with: summary, key_findings, sources, methodology, confidence_score',
    evaluationCriteria: ['accuracy', 'completeness', 'source_quality', 'relevance']
  },
  analysis: {
    system: 'You are a strategic analyst evaluating research findings.',
    objective: 'Analyze research for vulnerabilities, opportunities, and strategic insights.',
    outputFormat: 'JSON with: analysis, risks, opportunities, strategic_implications, confidence_score',
    evaluationCriteria: ['critical_thinking', 'risk_assessment', 'strategic_depth', 'actionability']
  },
  plan: {
    system: 'You are a strategic planner creating actionable implementation plans.',
    objective: 'Develop comprehensive, actionable implementation strategies.',
    outputFormat: 'JSON with: strategy, action_items, timeline, resources, success_metrics, confidence_score',
    evaluationCriteria: ['feasibility', 'completeness', 'resource_planning', 'measurability']
  }
};

const template = promptTemplates[phase];
let prompt = `${template.system}\n\n`;
prompt += `Phase: ${phase.toUpperCase()} - Round ${round}\n`;
prompt += `Objective: ${template.objective}\n\n`;
prompt += `User Request: ${userInput}\n\n`;

// Inject context from previous phases
if (phase === 'analysis' && documents.research) {
  prompt += `Research Context:\n${JSON.stringify(documents.research, null, 2)}\n\n`;
}

if (phase === 'plan' && documents.research && documents.analysis) {
  prompt += `Research Context:\n${JSON.stringify(documents.research, null, 2)}\n\n`;
  prompt += `Analysis Context:\n${JSON.stringify(documents.analysis, null, 2)}\n\n`;
}

// Add refinement context
if (round > 1 && refinementHistory.length > 0) {
  const lastFeedback = refinementHistory[refinementHistory.length - 1];
  prompt += `Previous Feedback:\n${lastFeedback.recommendations.join('\n')}\n\n`;
  prompt += `Address these points:\n`;
  lastFeedback.recommendations.forEach((rec, i) => {
    prompt += `${i + 1}. ${rec}\n`;
  });
  prompt += `\n`;
}

// Add consensus context
if (consensusScores.length > 0) {
  const avgScore = consensusScores.reduce((a, b) => a + b, 0) / consensusScores.length;
  prompt += `Previous Consensus Score: ${avgScore.toFixed(1)}%\n`;
  prompt += `Target: ${state.consensusThreshold}%\n\n`;
}

prompt += `Instructions:\n`;
prompt += `1. ${template.objective}\n`;
prompt += `2. Use the specified output format\n`;
prompt += `3. Ensure high confidence_score (80%+) based on: ${template.evaluationCriteria.join(', ')}\n`;
prompt += `4. Provide actionable, well-reasoned insights\n`;
prompt += `5. Return valid JSON only\n\n`;
prompt += `Output Format: ${template.outputFormat}`;

return {
  prompt,
  phase,
  round,
  template,
  state
};

// Multi-agent execution with load balancing and error handling
const { prompt, phase, round, state } = $input.first().json;

// Agent configurations with fallbacks
const agents = [
  {
    id: 'qwen3',
    name: 'Qwen3 Coder',
    model: 'qwen2.5-72b-instruct',
    maxTokens: 4000,
    temperature: 0.7,
    timeout: 45000,
    priority: 'high'
  },
  {
    id: 'mistral',
    name: 'Mistral Small 3.2',
    model: 'mistral-small-latest',
    maxTokens: 3000,
    temperature: 0.6,
    timeout: 30000,
    priority: 'medium'
  },
  {
    id: 'deepseek',
    name: 'DeepSeek R1',
    model: 'deepseek-chat',
    maxTokens: 4000,
    temperature: 0.5,
    timeout: 45000,
    priority: 'high'
  },
  {
    id: 'nemotron',
    name: 'NVIDIA Nemotron',
    model: 'gpt-4o',
    maxTokens: 4000,
    temperature: 0.6,
    timeout: 45000,
    priority: 'high'
  },
  {
    id: 'llama',
    name: 'Meta Llama 3.3',
    model: 'gpt-4o-mini',
    maxTokens: 3000,
    temperature: 0.7,
    timeout: 30000,
    priority: 'medium'
  },
  {
    id: 'kimi',
    name: 'Moonshot Kimi',
    model: 'gpt-4o',
    maxTokens: 4000,
    temperature: 0.8,
    timeout: 45000,
    priority: 'medium'
  }
];

// Filter active agents
const activeAgents = agents.filter(agent => 
  state.agentPerformance.active.includes(agent.id)
);

if (activeAgents.length === 0) {
  throw new Error('No active agents available');
}

// Prepare agent execution data
const agentExecutions = activeAgents.map(agent => ({
  agentId: agent.id,
  agentName: agent.name,
  model: agent.model,
  maxTokens: agent.maxTokens,
  temperature: agent.temperature,
  timeout: agent.timeout,
  prompt,
  phase,
  round,
  timestamp: new Date().toISOString()
}));

return {
  agentExecutions,
  totalAgents: activeAgents.length,
  phase,
  round,
  state
};

// Enhanced response aggregation with quality scoring
const responses = [];
const errors = [];
const performanceMetrics = {};

// Process all agent responses
$input.all().forEach((item, index) => {
  const execution = item.json;

  if (execution.choices && execution.choices[0]) {
    try {
      // Parse response content
      const content = execution.choices[0].message.content;
      let parsedContent;

      try {
        parsedContent = JSON.parse(content);
      } catch (parseError) {
        // Handle non-JSON responses
        parsedContent = {
          raw_content: content,
          parse_error: parseError.message,
          confidence_score: 50
        };
      }

      // Calculate quality score
      const qualityScore = calculateQualityScore(parsedContent, execution.phase);

      responses.push({
        agentId: execution.agentId,
        agentName: execution.agentName,
        content: parsedContent,
        qualityScore,
        timestamp: execution.timestamp,
        model: execution.model,
        responseTime: execution.responseTime || 0
      });

      // Track performance
      performanceMetrics[execution.agentId] = {
        qualityScore,
        responseTime: execution.responseTime || 0,
        success: true
      };

    } catch (error) {
      errors.push({
        agentId: execution.agentId,
        agentName: execution.agentName,
        error: error.message,
        timestamp: execution.timestamp
      });

      performanceMetrics[execution.agentId] = {
        success: false,
        error: error.message
      };
    }
  } else {
    errors.push({
      agentId: execution.agentId || `unknown_${index}`,
      agentName: execution.agentName || 'Unknown Agent',
      error: 'No valid response received',
      timestamp: new Date().toISOString()
    });
  }
});

// Sort responses by quality score
responses.sort((a, b) => b.qualityScore - a.qualityScore);

// Calculate aggregate metrics
const totalResponses = responses.length;
const avgQualityScore = totalResponses > 0 ? 
  responses.reduce((sum, r) => sum + r.qualityScore, 0) / totalResponses : 0;

const aggregatedData = {
  responses,
  errors,
  performanceMetrics,
  totalResponses,
  avgQualityScore,
  phase: $input.first().json.phase,
  round: $input.first().json.round,
  timestamp: new Date().toISOString()
};

// Quality scoring function
function calculateQualityScore(content, phase) {
  let score = 0;

  // Base score for valid JSON
  if (content && typeof content === 'object') {
    score += 20;
  }

  // Confidence score (if available)
  if (content.confidence_score && typeof content.confidence_score === 'number') {
    score += Math.min(content.confidence_score * 0.5, 40);
  }

  // Content completeness
  if (content.summary || content.analysis || content.strategy) {
    score += 20;
  }

  // Phase-specific scoring
  switch (phase) {
    case 'research':
      if (content.sources && content.key_findings) score += 20;
      break;
    case 'analysis':
      if (content.risks && content.opportunities) score += 20;
      break;
    case 'plan':
      if (content.action_items && content.timeline) score += 20;
      break;
  }

  return Math.min(score, 100);
}

return aggregatedData;

// Advanced committee evaluation with multiple evaluators
const aggregatedData = $input.first().json;
const { responses, phase, round, avgQualityScore } = aggregatedData;

// Committee evaluation prompt
const evaluationPrompt = `Committee Evaluation - ${phase.toUpperCase()} Phase\n\n` +
  `Round: ${round}\n` +
  `Total Responses: ${responses.length}\n` +
  `Average Quality Score: ${avgQualityScore.toFixed(1)}%\n\n` +
  `Agent Responses:\n` +
  responses.map((r, i) => 
    `\nAgent ${i + 1} (${r.agentName}):\n` +
    `Quality Score: ${r.qualityScore}%\n` +
    `Content: ${JSON.stringify(r.content, null, 2)}`
  ).join('\n') +
  `\n\nEvaluation Instructions:\n` +
  `1. Analyze response quality, consistency, and alignment\n` +
  `2. Calculate consensus score (0-100%)\n` +
  `3. Identify key divergence points and areas of agreement\n` +
  `4. Provide specific recommendations for improvement\n` +
  `5. Assess overall phase completion readiness\n` +
  `6. Return JSON with: consensus_score, divergence_points, recommendations, readiness_assessment, quality_analysis`;

// Prepare evaluation package for committee
const committeePackage = {
  evaluationPrompt,
  responses,
  phase,
  round,
  avgQualityScore,
  timestamp: new Date().toISOString()
};

return committeePackage;

// Consensus decision engine with intelligent routing
const committeeResponse = $input.first().json;
const committeePackage = $input.first().json.committeePackage;

let consensusScore = 0;
let divergencePoints = [];
let recommendations = [];
let readinessAssessment = 'incomplete';
let qualityAnalysis = {};

// Parse committee evaluation
if (committeeResponse.choices && committeeResponse.choices[0]) {
  try {
    const content = committeeResponse.choices[0].message.content;
    const parsed = JSON.parse(content);

    consensusScore = parsed.consensus_score || 0;
    divergencePoints = parsed.divergence_points || [];
    recommendations = parsed.recommendations || [];
    readinessAssessment = parsed.readiness_assessment || 'incomplete';
    qualityAnalysis = parsed.quality_analysis || {};

  } catch (parseError) {
    // Fallback parsing for non-JSON responses
    const content = committeeResponse.choices[0].message.content;

    // Extract consensus score using regex
    const scoreMatch = content.match(/consensus_score[\s:]*([0-9]+)/i);
    if (scoreMatch) consensusScore = parseInt(scoreMatch[1]);

    // Extract recommendations
    const recMatches = content.match(/recommendation[\s:]*([^\n]+)/gi);
    if (recMatches) {
      recommendations = recMatches.map(rec => rec.replace(/^recommendation[\s:]*/i, '').trim());
    }
  }
}

// Decision logic
const hasConsensus = consensusScore >= committeePackage.consensusThreshold || 85;
const canRetry = committeePackage.round < committeePackage.maxRounds || 4;
const isReady = readinessAssessment === 'ready' || consensusScore >= 90;

// Determine next action
let nextAction = 'retry';
if (hasConsensus && isReady) {
  nextAction = 'proceed';
} else if (!canRetry) {
  nextAction = 'finalize';
} else if (consensusScore < 50) {
  nextAction = 'escalate';
}

const decision = {
  consensusScore,
  divergencePoints,
  recommendations,
  readinessAssessment,
  qualityAnalysis,
  hasConsensus,
  canRetry,
  isReady,
  nextAction,
  phase: committeePackage.phase,
  round: committeePackage.round,
  timestamp: new Date().toISOString()
};

return decision;

// Document synthesis with quality enhancement
const decision = $input.first().json;
const committeePackage = $input.first().json.committeePackage;
const responses = committeePackage.responses;

// Create enhanced synthesis prompt
let synthesisPrompt = `Document Synthesis - ${decision.phase.toUpperCase()} Phase\n\n`;

synthesisPrompt += `Consensus Score: ${decision.consensusScore}%\n`;
synthesisPrompt += `Readiness: ${decision.readinessAssessment}\n`;
synthesisPrompt += `Number of Responses: ${responses.length}\n\n`;

synthesisPrompt += `Quality Analysis:\n${JSON.stringify(decision.qualityAnalysis, null, 2)}\n\n`;

synthesisPrompt += `Top Responses (by quality score):\n`;
responses.slice(0, 3).forEach((response, index) => {
  synthesisPrompt += `\n${index + 1}. ${response.agentName} (Score: ${response.qualityScore}%)\n`;
synthesisPrompt += `Content: ${JSON.stringify(response.content, null, 2)}\n`;
});

if (decision.divergencePoints.length > 0) {
  synthesisPrompt += `\nDivergence Points:\n${decision.divergencePoints.join('\n')}\n\n`;
}

synthesisPrompt += `Synthesis Instructions:\n`;
synthesisPrompt += `1. Create a comprehensive, professional document\n`;
synthesisPrompt += `2. Resolve contradictions using highest quality responses\n`;
synthesisPrompt += `3. Highlight areas of strong consensus\n`;
synthesisPrompt += `4. Address divergence points with balanced perspective\n`;
synthesisPrompt += `5. Ensure document meets publication standards\n`;
synthesisPrompt += `6. Return structured document with executive summary, main content, and appendices`;

return {
  synthesisPrompt,
  decision,
  phase: decision.phase,
  round: decision.round,
  responses: responses.slice(0, 3)
};

// State management and phase transition
const decision = $input.first().json;
const currentState = $input.first().json.state;
const phase = decision.phase;
const round = decision.round;

// Update state based on decision
const updatedState = { ...currentState };

// Store consensus data
updatedState.consensusScores.push({
  phase,
  round,
  score: decision.consensusScore,
  timestamp: new Date().toISOString()
});

// Store refinement history if retrying
if (decision.nextAction === 'retry') {
  updatedState.refinementHistory.push({
    round,
    phase,
    recommendations: decision.recommendations,
    consensusScore: decision.consensusScore,
    timestamp: new Date().toISOString()
  });
  updatedState.round = round + 1;
}

// Phase transition logic
if (decision.nextAction === 'proceed') {
  const phaseOrder = ['research', 'analysis', 'plan', 'complete'];
  const currentIndex = phaseOrder.indexOf(phase);
  const nextPhase = phaseOrder[currentIndex + 1] || 'complete';

  if (nextPhase === 'complete') {
    updatedState.phase = 'complete';
    updatedState.status = 'completed';
    updatedState.completedAt = new Date().toISOString();
  } else {
    updatedState.phase = nextPhase;
    updatedState.round = 1;
    updatedState.refinementHistory = [];
  }
}

// Update agent performance
if (decision.qualityAnalysis.agentPerformance) {
  updatedState.agentPerformance = {
    ...updatedState.agentPerformance,
    ...decision.qualityAnalysis.agentPerformance
  };
}

return {
  updatedState,
  decision,
  nextAction: decision.nextAction
};

// Final report generation with comprehensive insights
const state = $input.first().json.updatedState;
const documents = state.documents;
const consensusScores = state.consensusScores;
const refinementHistory = state.refinementHistory;

// Calculate performance metrics
const totalPhases = 3;
const completedPhases = Object.values(documents).filter(doc => doc !== null).length;
const avgConsensus = consensusScores.length > 0 ? 
  consensusScores.reduce((sum, cs) => sum + cs.score, 0) / consensusScores.length : 0;
const totalRefinements = refinementHistory.length;

// Generate executive summary
const executiveSummary = {
  workflow_status: 'completed',
  completion_date: state.completedAt,
  total_phases: totalPhases,
  completed_phases: completedPhases,
  average_consensus: avgConsensus.toFixed(1) + '%',
  total_refinements: totalRefinements,
  workflow_duration: calculateDuration(state.timestamp, state.completedAt),
  key_achievements: generateKeyAchievements(documents, consensusScores)
};

// Comprehensive final report
const finalReport = {
  executive_summary,
  detailed_findings: {
    research: documents.research || { status: 'not_completed' },
    analysis: documents.analysis || { status: 'not_completed' },
    plan: documents.plan || { status: 'not_completed' }
  },
  performance_analysis: {
    consensus_trends: consensusScores,
    refinement_analysis: refinementHistory,
    agent_performance: state.agentPerformance,
    quality_metrics: {
      overall_quality: avgConsensus,
      phase_completion_rate: (completedPhases / totalPhases) * 100,
      refinement_efficiency: totalRefinements / totalPhases
    }
  },
  recommendations: generateRecommendations(documents, consensusScores),
  metadata: {
    workflow_id: state.workflowId,
    generated_at: new Date().toISOString(),
    version: '2.0',
    total_execution_time: calculateDuration(state.timestamp, state.completedAt)
  }
};

// Helper functions
function calculateDuration(start, end) {
  if (!start || !end) return 'unknown';
  const duration = new Date(end) - new Date(start);
  const minutes = Math.floor(duration / 60000);
  const seconds = Math.floor((duration % 60000) / 1000);
  return `${minutes}m ${seconds}s`;
}

function generateKeyAchievements(docs, scores) {
  const achievements = [];
  if (docs.research) achievements.push('Comprehensive research completed');
  if (docs.analysis) achievements.push('Strategic analysis finalized');
  if (docs.plan) achievements.push('Implementation plan developed');
  if (scores.length > 0) achievements.push(`Average consensus: ${avgConsensus.toFixed(1)}%`);
  return achievements;
}

function generateRecommendations(docs, scores) {
  const recommendations = [];

  if (avgConsensus < 80) {
    recommendations.push('Consider additional refinement rounds for future workflows');
  }

  if (docs.research && docs.analysis && docs.plan) {
    recommendations.push('All phases completed successfully - proceed with implementation');
  }

  if (scores.some(s => s.score < 70)) {
    recommendations.push('Review low-consensus phases for quality improvement');
  }

  return recommendations;
}

return {
  finalReport,
  state,
  timestamp: new Date().toISOString()
};

